using namespace std;

long long solve(long long m, long long n, vector<vector<long long>> waitCost) {
    if (m == 1 && n == 1) {
        return 1;
    }

    long long inf = 1LL << 62;
    vector<vector<long long>> dp(m, vector<long long>(n, inf));

    dp[0][0] = 1;

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (i == 0 && j == 0) continue;

            long long entry_cost = (long long)(i + 1) * (long long)(j + 1);
