            if (i == m - 1 && j == n - 1) {
                cell_cost = entry_cost;
            } else {
                cell_cost = entry_cost + waitCost[i][j];
            }

            long long min_prev = inf;
            if (i - 1 >= 0) {
                min_prev = min(min_prev, dp[i - 1][j]);
            }
            if (j - 1 >= 0) {
                min_prev = min(min_prev, dp[i][j - 1]);
            }

            if (min_prev == inf) {
                dp[i][j] = inf;
            } else {
                dp[i][j] = min_prev + cell_cost;
            }
        }
    }

    return dp[m - 1][n - 1];
}
